#include <stdio.h>
#include <stdlib.h>

int* findRepresentation(int product, int P) {
    int* representation = (int*)malloc(4 * sizeof(int));
    for (int a = 0; a * a <= product; a++) {
        for (int b = a; b * b <= product; b++) {
            for (int c = b; c * c <= product; c++) {
                for (int d = c; d * d <= product; d++) {
                    if ((a * a + b * b + c * c + d * d) % P == product % P) {
                        representation[0] = a;
                        representation[1] = b;
                        representation[2] = c;
                        representation[3] = d;
                        return representation;
                    }
                }
            }
        }
    }
    return NULL;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q, P;
        scanf("%d %d %d", &N, &Q, &P);
        int* A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        while (Q--) {
            int type;
            scanf("%d", &type);
            if (type == 1) {
                int X, Y;
                scanf("%d %d", &X, &Y);
                A[X - 1] = Y;
            } else {
                int L, R;
                scanf("%d %d", &L, &R);
                int product = 1;
                for (int i = L - 1; i < R; i++) {
                    product = (product * A[i]) % P;
                }
                int* representation = findRepresentation(product, P);
                if (representation != NULL) {
                    printf("%d %d %d %d\n", representation[0], representation[1], representation[2], representation[3]);
                } else {
                    printf("-1\n");
                }
            }
        }
        free(A);
    }
    return 0;
}

