import java.util.Scanner;

public class Main {
    public static int[] findRepresentation(int product, int P) {
        for (int a = 0; a * a <= product; a++) {
            for (int b = a; b * b <= product; b++) {
                for (int c = b; c * c <= product; c++) {
                    for (int d = c; d * d <= product; d++) {
                        if ((a * a + b * b + c * c + d * d) % P == product % P) {
                            return new int[] {a, b, c, d};
                        }
                    }
                }
            }
        }
        return null;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int Q = scanner.nextInt();
            int P = scanner.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = scanner.nextInt();
            }
            while (Q-- > 0) {
                int type = scanner.nextInt();
                if (type == 1) {
                    int X = scanner.nextInt();
                    int Y = scanner.nextInt();
                    A[X - 1] = Y;
                } else {
                    int L = scanner.nextInt();
                    int R = scanner.nextInt();
                    int product = 1;
                    for (int i = L - 1; i < R; i++) {
                        product = (product * A[i]) % P;
                    }
                    int[] representation = findRepresentation(product, P);
                    if (representation != null) {
                        System.out.println(representation[0] + " " + representation[1] + " " + representation[2] + " " + representation[3]);
                    } else {
                        System.out.println(-1);
                    }
                }
            }
        }
    }
}

